"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["6190"],{27679(e,i,a){a.r(i),a.d(i,{default:()=>r});var t=a(74848),o=a(47643),n=JSON.parse('{"id":102,"it":{"title":"Dati dello sviluppatore","prompt":"I want you to act as a Developer Relations consultant. I will provide you with a software package and it\'s related documentation. Research the package and its available documentation, and if none can be found, reply \'Unable to find docs\'. Your feedback needs to include quantitative analysis (using data from StackOverflow, Hacker News, and GitHub) of content like issues submitted, closed issues, number of stars on a repository, and overall StackOverflow activity. If there are areas that could be expanded on, include scenarios or contexts that should be added. Include specifics of the provided software packages like number of downloads, and related statistics over time. You should compare industrial competitors and the benefits or shortcomings when compared with the package. Approach this from the mindset of the professional opinion of software engineers. Review technical blogs and websites (such as TechCrunch.com or Crunchbase.com) and if data isn\'t available, reply \'No data available\'. Respond in Italian. My first request is express [link].","description":"Vorrei che lei agisse come consulente per le relazioni con gli sviluppatori. Vi fornir\xf2 un pacchetto software e la relativa documentazione. Cercate il pacchetto e la documentazione disponibile e, se non riuscite a trovarla, rispondete con \\"Impossibile trovare la documentazione\\". Il vostro feedback deve includere analisi quantitative (utilizzando i dati di StackOverflow, Hacker News e GitHub) di aspetti quali i problemi inviati, i problemi chiusi, il numero di stelle sul repository e l\'attivit\xe0 complessiva su StackOverflow. Se ci sono aree che possono essere ampliate, includere scenari o contesti che dovrebbero essere aggiunti. Includete informazioni specifiche sui pacchetti offerti, come il numero di download e le statistiche rilevanti nel tempo. Dovreste confrontare i concorrenti del settore e i vantaggi o gli svantaggi rispetto al pacchetto. Affrontate la questione con la mentalit\xe0 dell\'opinione professionale di un ingegnere del software. Esaminate i blog e i siti web di tecnologia (ad esempio, TechCrunch.com o Crunchbase.com) e rispondete \\"no data\\" se non ci sono dati.","remark":"Aggregare i dati rilevanti su GitHub, StackOverflow e Hacker News relativi al progetto. Tuttavia, questo metodo non \xe8 applicabile ai progetti nazionali e l\'accuratezza statistica \xe8 media."},"tags":["code"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-developer-relations-consultant","count":503,"related":[{"id":90,"title":"Problemi di programmazione IT","remark":"Comunit\xe0 di programmazione per la simulazione che risponde alle vostre domande e fornisce codice risolutivo."},{"id":218,"title":"Aiuto alla programmazione CAN","remark":"Lasciate che sia l\'intelligenza artificiale a porre domande e a guidare l\'uomo, passo dopo passo, attraverso il codice. Raccolto da Snackprompt, condiviso da @fuxinsen."},{"id":173,"title":"interprete di codice","remark":"Lasciare che l\'intelligenza artificiale spieghi cosa fa ogni passo del codice. Contributo di @Tractor1928, successivamente modificato da @yiqiongwu."}],"metaTitle":"Consulente DevRel: Analisi Pacchetti","metaDescription":"Valuti software? Analisi quantitativa di GitHub e competitor. Valuta la salute della community per decisioni informate. Provalo ora.","faq":[{"q":"L\'AI vede davvero le stelle GitHub correnti?","a":"No. Non essendo online, tutti i numeri sono \xabimpressioni\xbb dal training, abbastanza buoni per librerie molto note (React, TensorFlow), pure congetture per quelle di nicchia. Per analisi developer reali usa libraries.io, GitHub API, Hacker News Search."},{"q":"Perch\xe9 per progetti di community locali (Vue, Element) \xe8 impreciso?","a":"Le community cinesi sono attive su Gitee, Juejin, SegmentFault, piattaforme poco presenti nei corpora di training. Per analisi su progetti domestici consulta le classifiche su quelle piattaforme direttamente; i numeri dell\'AI sono spesso bassi o errati."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,t.jsx)(o.A,{prompt:n,currentLanguage:"it"})}}}]);